import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Sample Fields',
    parameters: {
      mode: 'manual',
      includeOtherFields: false,
      assignments: {
        assignments: [
          {
            id: 'field-message',
            name: 'message',
            value: 'Hello, this is a test value!',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('wf-artifact-click-test', 'artifact click test')
  .add(manualTrigger)
  .to(setNode);
